Here's how to write proper MSTest tests for your `DataFetcher`, covering success, timeout, and cancellation:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_SuccessfulResponse_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHandler(new HttpResponseMessage
        {
            StatusCode = HttpStatusCode.OK,
            Content = new StringContent("hello world"),
        });
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act
        var result = await fetcher.FetchAsync("https://example.com", _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_ServerError_ThrowsHttpRequestException()
    {
        // Arrange
        var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.InternalServerError));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act & Assert
        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com", _testContext.CancellationToken));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceled()
    {
        // Arrange
        var handler = new FakeHandler(delay: TimeSpan.FromSeconds(30));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // Cancel immediately

        // Act & Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_Timeout_RespectsCancellation()
    {
        // Arrange — handler that never responds quickly
        var handler = new FakeHandler(delay: TimeSpan.FromSeconds(30));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);
        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(100));

        // Act & Assert — should cancel well before [Timeout]
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // Minimal fake handler to avoid external mocking libraries
    private sealed class FakeHandler : HttpMessageHandler
    {
        private readonly HttpResponseMessage? _response;
        private readonly TimeSpan _delay;

        public FakeHandler(HttpResponseMessage response) => _response = response;

        public FakeHandler(TimeSpan delay) => _delay = delay;

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (_delay > TimeSpan.Zero)
            {
                await Task.Delay(_delay, cancellationToken);
            }

            return _response ?? new HttpResponseMessage(HttpStatusCode.OK);
        }
    }
}
```

**Key patterns used:**

| Pattern | Why |
|---------|-----|
| `TestContext` via constructor | Enables `readonly` + nullability safety |
| `[Timeout(5000)]` + `_testContext.CancellationToken` | Cooperative timeout — test is cancelled cleanly if it hangs |
| `Assert.ThrowsExactlyAsync<T>` | Tests exact exception type (not `[ExpectedException]`) |
| Separate `CancellationTokenSource` for cancellation tests | Decouples test timeout from the scenario under test |
| `sealed` class + `sealed` handler | Performance best practice |

The `[Timeout]` attribute triggers `TestContext.CancellationToken`, so always pass that token to your async calls. For cancellation-specific tests, create your own `CancellationTokenSource` so you control exactly when cancellation fires.
